const readSecret = (k) => {
  let v = null;
  try { v = $env[k]; } catch (e) {}
  if (v === null || v === undefined || v === '') {
    try { v = typeof $vars !== 'undefined' ? $vars[k] : null; } catch (e) {}
  }
  return (v === null || v === undefined) ? '' : String(v);
};
// Spend guard for the OPTIONAL summary line (fail-open): no reachable numeric cap or
// budget exhausted => summary NOT ok, the deterministic digest ships regardless.
const CAP = Number(readSecret("DIRNOTIF_LLM_DAILY_BUDGET_USD"));
const capOk = Number.isFinite(CAP) && CAP > 0;
const s = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0, 10);
if (s.dirnotif_digest_spend_day !== today) { s.dirnotif_digest_spend_day = today; s.dirnotif_digest_spend_usd = 0; }
const summaryOk = capOk && (Number(s.dirnotif_digest_spend_usd) || 0) < CAP;

// PAT-4 guard: hosted n8n Cloud hands JSON bodies back PRE-PARSED (LIVE 2026-07-07)
// — parse OBJECT-FIRST, never .toString()+JSON.parse.
const rows = [];
for (const it of $input.all()) {
  const j = it.json || {};
  const body = (function(__b){ if (__b && typeof __b === 'object') return __b; const __s = String(__b ?? '').trim(); if (!__s) return []; try { return JSON.parse(__s); } catch (__e) { return []; } })(j.body);
  if (Array.isArray(body)) rows.push(...body);
  else if (body && typeof body === 'object') rows.push(body);
}
const esc = (x) => String(x == null ? '' : x)
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const digestDate = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
const byBand = { HOT: [], WARM: [], REVIEW: [], COLD: [] };
for (const r of rows) {
  const b = (r && r.band && byBand[r.band]) ? r.band : 'COLD';
  byBand[b].push(r || {});
}
const line = (r) => {
  const title = esc(r.title || r.category || '(untitled)');
  const why = r.why ? ' — ' + esc(r.why) : '';
  const angle = r.suggested_angle ? '<br><em>Angle: ' + esc(r.suggested_angle) + '</em>' : '';
  const link = r.url ? ' <a href="' + esc(r.url) + '">open</a>' : '';
  return '<li><strong>' + title + '</strong>' + why + link + angle + '</li>';
};
const section = (label, items) => items.length
  ? '<h3>' + label + ' (' + items.length + ')</h3><ul>' + items.map(line).join('') + '</ul>'
  : '';
const parts = [
  section('🔥 HOT', byBand.HOT),
  section('WARM', byBand.WARM),
  section('REVIEW — verify these (false-negative catch)', byBand.REVIEW),
  section('COLD', byBand.COLD),
];
const total = rows.length;
const hot = byBand.HOT.length;
const bodyHtml = total
  ? parts.filter(Boolean).join('')
  : '<p>No qualified community leads in the last day.</p>';
const subject = 'Community Lead Digest — ' + digestDate + ' (' + total + ' leads, ' + hot + ' hot)';
// The summary prompt is decision support; the LLM line is prepended only if enabled.
const summaryPrompt = 'Summarise this daily community-lead digest in ONE plain sentence '
  + 'for a busy founder. Digest:\n' + rows.map((r) =>
      '- [' + (r.band || '?') + '] ' + (r.title || r.category || '') + (r.why ? ': ' + r.why : '')
    ).join('\n');
return [{ json: {
  __digest_date: digestDate,
  __lead_count: total,
  __hot_count: hot,
  __subject: subject,
  __body_html: bodyHtml,
  __summary_ok: summaryOk && total > 0,
  __summary_prompt: summaryPrompt,
} }];

const ctx = $('Compose Digest').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const c = (ctx[i] || ctx[0] || { json: {} }).json;
  const parsed = (function(__b){ if (__b && typeof __b === 'object') return __b; const __s = String(__b ?? '').trim(); if (!__s) return null; try { return JSON.parse(__s); } catch (__e) { return null; } })(resp.body);
  let summary = null;
  const content = parsed && parsed.choices && parsed.choices[0]
    && parsed.choices[0].message && parsed.choices[0].message.content;
  if (typeof content === 'string' && content.trim()) summary = content.trim().slice(0, 400);
  const html = summary
    ? '<p><strong>Summary:</strong> ' + summary.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</p>' + c.__body_html
    : c.__body_html;
  out.push({ json: Object.assign({}, c, { __body_html: html }) });
}
return out;

const ctx = $('Compose Digest').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const c = (ctx[i] || ctx[0] || { json: {} }).json;
  const status = Number(resp.statusCode || 0);
  const parsed = (function(__b){ if (__b && typeof __b === 'object') return __b; const __s = String(__b ?? '').trim(); if (!__s) return null; try { return JSON.parse(__s); } catch (__e) { return null; } })(resp.body);
  const messageId = (parsed && (parsed.id || parsed.message_id)) || null;
  out.push({ json: Object.assign({}, c, {
    __sent_at: (status >= 200 && status < 300) ? new Date().toISOString() : null,
    __message_id: messageId,
  }) });
}
return out;
